css:
/* 作者：栗子*/
/* 禁商禁二传 */
/* 可自用二改 */
/* 感谢各位美化老师们的慷慨分享（抹泪）*/
/* 感谢群友帮我测美化 */

/*如果想要调宽气泡宽度，就调mes_block400的值，然后调长聊天信头部和底部的width值，再调整位置*/

@import url("https://fontsapi.zeoseven.com/488/main/result.css");

/* == 全局设置 & 字体== */
:root {
    --topBarBlockSize: 27px;
    --mainFontSize: 12px;/* 文本字体大小 */
    --box-border-radius: 5px;
    --top-distance: 7px;
    --scroll-width: 5px;
    --icon-size: var(--mainFontSize);

/* == 如果你想调宽气泡，请调这里 == */
    --mes-block-width: 400px;/* 聊天宽度 */
    --mes--decoration-top-width:400px;/* 聊天信头部装饰图大小 */
    --mes--decoration-bottom-width:349.6px;/* 聊天信底部装饰图大小 */

/*调完后如果发现文本超过了气泡宽度，请调这里，调大*/
   --mes-pad-right: 24px;/*右边距*/
   --mes-pad-left: 58px;/*左边距*/

 /* == 左右位置微调变量，除了最后一个，其他都是往左调就把数值调小 == */

    --mes-decoration-top-left: 50%;/* 聊天信头部装饰图位置 */
    --mes-decoration-bottom-offset: 2.2px;/* 聊天信信底部装饰图位置 */
   --mes-pos-left: -130px;/*楼层时间消耗这三个的位置*/ 
    --user-mes-block-decoration-left: 260px;/* 用户消息玫瑰印章 */
    --avatar-left-pos: -160px;/* 头像位置 */
    --user-name-left-pos: 35%;/* 用户名字位置 */
    --char-name-left-pos: 50%;/* 角色名字位置 */
    --user-timestamp-left-pos: -36%;/* 用户时间戳位置 */
    --char-timestamp-left-pos: -120px;/* 角色时间戳位置 */
    --extra-buttons-right-pos: -15px;/* 消息按钮（左边纽扣）位置，调大往左移 */
}

body,
.text_pole:not(#completion_prompt_manager_list),
select,
textarea:not(#send_textarea),
input{
    font-family: "STDongGuanTi";
    font-weight: 500;
}

code,
code * {
    font-family: "STDongGuanTi" ;
    font-weight: normal ;
}

/* == 聊天主界面布局 == */
/* 二改自kakaa老师的双色盒子 */
#sheld {
    height: calc(100dvh - var(--topBarBlockSize) - var(--top-distance) - 1px);
}

#chat {
    background: transparent !important;
    background-color: transparent !important;
    backdrop-filter: none;
    border: none !important;
    overflow-y: scroll;
    align-items: center;
    max-height: calc(100dvh - var(--topBarBlockSize)) !important;
    padding: calc(var(--scroll-width) + 4px) 0 var(--scroll-width) var(--scroll-width);
    border-radius: 0 0 var(--box-border-radius) var(--box-border-radius);
}

@supports (-webkit-touch-callout: none) {
    #chat {
        padding-right: var(--scroll-width);
    }
}
#left-nav-panel.drawer-content{
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-repeat: repeat-y !important;
    background-size: 100% auto !important;   
}
#user-settings-block.drawer-content{
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-repeat: repeat-y !important;
    background-size: 100% auto !important;   
}
/* 滚动条样式 */
::-webkit-scrollbar {
    width: 5px;
}

::-webkit-scrollbar-track {
    background: transparent;
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
    background-color: #ffffff;
    box-shadow: none;
    border: 0;
}

/* == 消息气泡 == */
.mes {
    width: 100%;
    padding: 40px 12px;
    margin-bottom: 125px!important;
   margin-top: 105px!important;
    display: flex;
    flex-direction: column;
    align-items: center;
    background-color: rgba(255, 255, 255, 0) !important;
    border:none!important;
    border-radius: 0;    
    box-shadow: none;    
    position: relative;
    overflow: visible !important;
}

/* 气泡背景装饰 */
.mes::after {
    content: "";
    position: absolute; 
    left: var(--mes-decoration-top-left);
    transform: translateX(-50%);
    top: -50px;
    width: var(--mes--decoration-top-width);
    height: 110px;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-size: cover;
    background-repeat: no-repeat;
    opacity: 1 !important;
    pointer-events: none;
    z-index: 99;
}
.mes::before {
    content: "";
    position: absolute;
    left: 50%;
    /* 原居中是translateX(-50%)，增加正数实现右移 */
    transform: translateX(calc(-50% + var(--mes-decoration-bottom-offset)));
    bottom: -109px;
    width: var(--mes--decoration-bottom-width);
    height: 120px;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-size: cover;
    background-repeat: no-repeat;
    background-position: center 50%;
    opacity: 1 !important;
    pointer-events: none;
    z-index: 5;
}


.mes_block {
    width: var(--mes-block-width) !important;
    max-width: none !important; 
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important;
    background-repeat: repeat-y !important; 
    background-size: var(--mes-block-width) auto !important;
    background-position: 0px 38px !important;
    border-radius: 0 !important; 
    padding: 100px var(--mes-pad-right) 25px var(--mes-pad-left) !important;
    position: relative !important;
    margin-top: 0 !important;
    min-height: 100px; 
    overflow: visible !important; 
    z-index: 10 !important;
}
[is_user=true].mes .mes_block::after {
     content: ""!important;
     position: absolute;
     left: var(--user-mes-block-decoration-left);
     bottom: -50px;  
     width: 80px; 
     height: 80px; 
     background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') no-repeat center/contain;
     z-index:9999;
     opacity:0.8;
     transform: translateZ(0); 
    will-change: transform; 
 }

/* ==头像与名字 == */
.mesAvatarWrapper {
    position: absolute;
    top: px !important;
    left: 75% !important;
    width:200px;
    height:30px;
    transform: none !important;
}

#chat .mes .avatar {
    position: relative;
    left: var(--avatar-left-pos);
    top:-60px;
    display: inline-block;
    padding: 8px;
    z-index: 999;
    transform: scale(0.3);
 }
#chat .mes .avatar img {
    width: 225px;
    height: 280px;
   top:120px;
   left:-122px;
    object-fit: cover;
    object-position: center 40%;
    transition: all 0.3s ease;
    position:relative;
    transform: rotate(12deg);
}

#chat .mes .avatar::before {
    content: "";
    position: absolute;
    top: 100px;
    left: -270px;
    width: calc(670%);
    height: calc(670%);
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: -1;
    pointer-events: none;
    opacity:1;
}

#chat .mes .avatar::after {
    content: "";
    position: absolute;
    top: 116px;
    left: -130px;
    width: calc(620%);
    height: calc(620%);
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 1;
    pointer-events: none;
    opacity:1;
    transform: rotate(12deg);
}


/* 头像选中框 */
.avatar-container.interactable.selected {
    outline: 3px solid #ffdbdb !important;
    padding: 3px;
}

.avatar-container {
    width: 80px !important;
    height: 80px !important;
    min-width: 80px !important;
    min-height: 80px !important;
}
.ch_name.flex-container.justifySpaceBEtween {
     position: static !important; 
 }
/* 名字栏 */
.mes .flex-container.alignItemsBaseline
{
    position: absolute !important; 
    bottom: -65px !important; 
    width: 100% !important;
    height: 40px;
    padding: 0 10px !important; 
    margin: 0 !important; 
    display: flex;
    align-items: center;
    justify-content: space-between;
    background-color: transparent !important; 
    border-radius: 5px;
    z-index: 100 !important; 
    pointer-events: none; 
}
.mes[is_user="true"] .name_text {
    font-size: 12px;
    font-weight: 400;
    color: #7d5a5a;
    position: relative;
    left: var(--user-name-left-pos);
    top: -30px;
    font-style: oblique;
    transform: translateX(-50%); 
    transform-origin: center;
    white-space: nowrap;
    text-align: center; 
}
.mes:not([is_user="true"]) .name_text {  
   font-size: 13px!important;
   font-weight:400;
   color:#7d5a5a;
   position: relative;
   left: var(--char-name-left-pos);  
   top: -30px ;
   font-style: oblique;
   transform: translateX(-50%);
   transform-origin: center;
}
.mes[is_user="true"] .timestamp {
    font-size: 11px;
    font-weight: 400;
    color: #7d5a5a;
    position: relative;
    left: var(--user-timestamp-left-pos);
    top: 0px;
    font-style: oblique;
    transform: translateX(-50%);
    transform-origin: center;

    white-space: nowrap;
    text-align: center;
}
.mes:not([is_user="true"]) .timestamp{   
   font-size:11px!important;
   font-weight:400!important;
   color:#7d5a5a;
   position: relative !important;
   left: var(--char-timestamp-left-pos) !important;  
   top: 0px !important;
   font-style: oblique;
}

#chat .name_text::before {  
    content: "𝑏y";
    color: #6a4a3c;
   margin-right: 10px;

}

/* 公共按钮样式 */
.mes_buttons {
    position: relative;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    top: 40px;
    height: auto;             
    background-color: transparent;
    border-radius: 5px;
    z-index: 9;
    overflow: visible;        
}
/* 编辑按钮图标替换 */
.mes_button.mes_edit.fa-pencil.interactable {
    position: relative;
    font-size: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    top: 75px;
    left:-10px;
    width: 46px;
    height: 46px;
    border: none;
    background: transparent;
    cursor: pointer;

}

.mes_button.mes_edit.fa-pencil.interactable::before {
    content: '' !important;
    display: block;
    width: 100%;
    height: 100%;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    font-size: 0;
    box-shadow: none!important;
}

/*  编辑菜单位置调整  */
/*源自Nuyoah老师*/
.mes_edit_buttons {
    /* 1. 核心定位指令 (不动) */
    position: absolute !important;
    z-index: 99 !important;
    /* 2.位置 */
    top: 90px !important;    
    right: 65px !important;   
    /* 3. 平时隐藏 (不想一直挡着就保留这两行) */
    opacity: 0 !important;
    pointer-events: none !important;
    transition: opacity 0.2s !important;
}

/* 4. 交互显示 (鼠标指上去才出来，不动) */
.mes:hover .mes_edit_buttons,
.mes.selected .mes_edit_buttons {
    opacity: 1 !important;
    pointer-events: auto !important;
}
/* 消息操作按钮图标替换 */
.mes_button.extraMesButtonsHint.fa-ellipsis.interactable {
    position: relative;
    margin-left: 0px;
    display: flex;
    align-items: center;
    justify-content: center;
    top: 75px;
    right: var(--extra-buttons-right-pos); 
    left: auto;
    width: 40px;
    height: 40px;
    border: none;
    background: transparent;
    cursor: pointer;
    z-index: 9999;
}
.mes_button.extraMesButtonsHint.fa-ellipsis.interactable::after {
    content: '' !important;
    position: absolute; 

    width: 100%;
    height: 100%;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    font-size: 0;
    box-shadow: none !important;
}
.extraMesButtons.visible{
position:relative;
top:70px;
opacity: 1 !important;
}

.mes_button.extraMesButtonsHint.fa-ellipsis.interactable::before {  
    content: "𝑇𝑂 𝑀𝑌 𝐿𝑂𝑉𝐸𝑅";
    color: #A45A52;
   margin-left: -360px;
   font-size:12.5px;

   position:relative;
}

/* 源自易碎蝶老师 */
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: blac !important;
opacity: 0.7 !important; 
}



/* ==消息内容与排版== */
.mes_text {
    padding: 50px -8px 40px 0px !important;
    z-index: 9999;
   font-weight: 500;
}

/* 隐藏开头的第一个和第二个换行符 */
/*源自NA老师*/
.mes_text p content > br:first-child {
    display: none;
}
.mes_text p {
    margin-bottom: 1em!important;
}

/* 代码块样式 */
.mes_text code {
    display: inline-block;
    background-color: rgba(255, 245, 245, 0.7) !important;
    padding: 6px 10px !important;
    margin: 5px 6px 5px 0 !important;
    color: #8a716a !important;
    border: 1px solid rgba(232, 196, 196, 0.4) !important;
    border-radius: 4px !important;
    letter-spacing: 0.2px !important;
    word-spacing: 0.5px !important;
    line-height: 1.4 !important;
    font-size: 0.95em !important;
    box-shadow: 
        inset 0 1px 3px rgba(255, 255, 255, 0.8),
        0 1px 2px rgba(232, 196, 196, 0.1) !important;
}

/* 块级代码样式 */
.mes_text pre code {
    display: block;
    background: linear-gradient(135deg, rgba(255, 250, 250, 0.9) 0%, rgba(248, 240, 245, 0.85) 100%) !important;
    padding: 18px 20px !important;
    margin: 16px 0 !important;
    border-left: 4px solid rgba(232, 196, 196, 0.6) !important;
    border-radius: 6px !important;
    border: 1px solid rgba(232, 196, 196, 0.3) !important;
    box-shadow: 
        0 3px 12px rgba(232, 196, 196, 0.08),
        inset 0 0 0 1px rgba(255, 255, 255, 0.6) !important;
    overflow-x: auto;
    line-height: 1.5 !important;
    font-size: 0.9em !important;
}



/* 引用块样式 */
.mes_text blockquote {
    background: 
        linear-gradient(135deg, rgba(255, 245, 245, 0.85) 15%, rgba(248, 240, 245, 0.75) 100%),
        url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat !important;
    margin: 20px 12px 24px 8px !important;
    padding: 24px 28px !important;
    border-left: 5px solid rgba(232, 196, 196, 0.7) !important;
    border-radius: 8px !important;
    border: 1px solid rgba(255, 255, 255, 0.4) !important;
box-shadow: 
        0 4px 20px rgba(232, 196, 196, 0.15),
        0 0 0 1px rgba(255, 255, 255, 0.8),
        inset 0 0 20px rgba(255, 255, 255, 0.6) !important;
    position: relative;
    font-size: 11px !important;
    line-height: 1.6 !important;
    color: #7a6a6a !important;    
    overflow: hidden;
}


/* 右下角装饰 */
.mes_text blockquote::before {
    content: "";
    position: absolute;
    display: inline-block;
    width: 80px;
    height: 80px;
    right: -20px;
    bottom: 12px;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-size: contain;
    background-repeat: no-repeat;
    opacity: 0.6;
    z-index: 2;
}

/* 首字母装饰 */
.mes_text blockquote p:first-of-type::first-letter {
    font-size: 2.2em;
    float: left;
    line-height: 1;
    margin-right: 8px;
    color: #d4a6a6;
    font-weight: normal;
    text-shadow: 1px 1px 3px rgba(255, 255, 255, 0.8);
    background: linear-gradient(135deg, #f0d6d6, #e8c4c4);
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    z-index: 2;
    position: relative;
}


.text-delete {
  text-decoration: line-through;
  text-decoration-color: #c9a794;
  text-decoration-style: solid; 
  text-decoration-thickness: 1px; 
}
hr {
  background-color: #e8d9d0; /* 低饱和粉棕色调 */
}
/*思维链 */
.mes_reasoning_summary {
    padding: 0 !important;
    margin: 0px 0px !important;
}

.mes_reasoning_header {
    position: relative !important;
    top: 5px !important;
    left: 8px !important;
     transform: none !important;
    transition: none !important;
    animation: none !important;
    width: 90% !important;
    height: 20px !important;
    color: transparent !important;
    font-size: 1em !important;
    background-color:rgba(225,225,225,0) !important;
    background-image: none !important;
    background-size: cover !important;
    background-position: center center !important;
}

.mes_reasoning_header.flex-container::before {
    content: "♡⁺₊ 𝓟𝓲𝓷𝓴 𝓑𝓪𝓷𝓭 𝓐𝓲𝓭 ₊⁺♡";
    position: absolute !important;
    top: 0% !important;
    left: 50% !important;
    transform: translate(-50%, -50%) !important;
    color: #7d5a5a !important;
    font-size: 1em !important;
    font-weight: 600 !important;
    letter-spacing: 1px !important;
    text-transform: uppercase !important;
    white-space: nowrap !important;
    z-index: 2 !important;
}

/* ==消息元数据 == */
.mesIDDisplay,
.tokenCounterDisplay,
.mes_timer {
    position: absolute !important;
    display: inline-block;
    top: 50px;
    left: var(--mes-pos-left) !important;
    width:200px;
    padding: 4px 10px;
    border-radius: 16px;
    background: rgba(225, 225, 225, 0);
    backdrop-filter: blur(0px);
    -webkit-backdrop-filter: blur(0px);
    border: 0px solid rgba(255, 255, 255, 0);
    color: #EE9CA7;
    font-style: italic;
    font-size: 14px;
    font-weight: 800！important;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
    z-index: 100;
}
.mesIDDisplay { top: 3px; }
.tokenCounterDisplay { top: 55px; }
.mes_timer { top: 28px; }

.mesIDDisplay:empty,
.tokenCounterDisplay:empty,
.mes_timer:empty {
    display: none !important;
}
 .mesIDDisplay::before, 
 .tokenCounterDisplay::before,
 .mes_timer::before {  
    color: #EE9CA7;
   margin-right: 10px; 
}

 .mesIDDisplay::before {
    content: "𝐿𝑒𝑡𝑡𝑟𝑒 𝑁𝑜.";
}

 .tokenCounterDisplay::before {
    content: "𝑊𝑜𝑟𝑑𝑠 𝐶𝑜𝑢𝑛𝑡𝑒𝑑 𝑎𝑡";
}
.mes_timer::before {
    content: "𝐷𝑒𝑠𝑝𝑎𝑡𝑐ℎ𝑒𝑑 𝐴𝑓𝑡𝑒𝑟";
}


.swipe_left.fa-solid.fa-chevron-left.interactable::before,
.swipe_right.fa-solid.fa-chevron-right.interactable::before {
    content: "" !important;
    /* 彻底覆盖 Font Awesome 的字体样式干扰 */
    font-family: initial !important;
    font-size: 0 !important;
    font-weight: normal !important;
    display: inline-block !important;
    width: 50px !important; 
    height: 50px !important;
    /* 核心：补充 background 完整属性，确保图片正常显示 */
  /*隐藏  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') !important;
    background-position: center !important;
    background-repeat: no-repeat !important;
    background-size: contain !important;
    /* 缩放后调整原点，避免偏移 */
    transform: scale(2) !important;
    transform-origin: center !important;
    vertical-align: middle;
    /* 防止缩放后被截断 */
